class MainActivity : ComponentActivity() {
    var tapCount = 0  // increases by 1 each time a button is tapped
}

// User taps the button 5 times -> tapCount = 5
// User then rotates the device from portrait to landscape
// User checks tapCount again

override fun onSaveInstanceState(outState: Bundle) {
    super.onSaveInstanceState(outState)
    outState.putInt("tapCount", tapCount)
}

override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    tapCount = savedInstanceState?.getInt("tapCount") ?: 0
}

override fun onResume() {
    super.onResume()
    startListeningToSensor()  // begins using battery and CPU
}

override fun onPause() {
    super.onPause()
    stopListeningToSensor()  // must match the start above
}

